import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate } from 'react-router-dom';

export default function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));
  const [orders, setOrders] = useState([]);

  // Сохраняем сессию
  const login = async (email, password) => {
    const res = await fetch('http://localhost:8000/index.php', {
      method: 'POST',
      body: JSON.stringify({ action: 'login', email, password })
    });
    const data = await res.json();
    if (data.id) {
      setUser(data);
      localStorage.setItem('user', JSON.stringify(data));
    } else {
      alert(data.error);
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
  };

  useEffect(() => {
    if (user) {
      const fetchOrders = () => {
        fetch(`http://localhost:8000/index.php?user_id=${user.id}`)
          .then(res => res.json())
          .then(data => setOrders(Array.isArray(data) ? data : []));
      };
      fetchOrders();
      const interval = setInterval(fetchOrders, 3000);
      return () => clearInterval(interval);
    }
  }, [user]);

  if (!user) {
    return <LoginScreen onLogin={login} />;
  }

  return (
    <Router>
      <div className="paradise-app">
        <header className="user-bar">
          <span>Привет, {user.company_name}!</span>
          <button onClick={logout} className="btn-logout">Выйти</button>
        </header>

        <Routes>
          <Route path="/" element={<Menu user={user} />} />
          <Route path="/profile" element={<Profile orders={orders} />} />
          {/* Другие роуты... */}
        </Routes>

        <nav className="bottom-nav">
          <Link to="/">🍴 Меню</Link>
          <Link to="/profile">👤 Профиль</Link>
        </nav>
      </div>
    </Router>
  );
}

// Компонент экрана входа
function LoginScreen({ onLogin }) {
  const [email, setEmail] = useState('');
  const [pass, setPass] = useState('');

  return (
    <div className="login-page">
      <div className="login-card">
        <h2>Etika Coffee</h2>
        <input type="email" placeholder="Email" onChange={e => setEmail(e.target.value)} />
        <input type="password" placeholder="Пароль" onChange={e => setPass(e.target.value)} />
        <button onClick={() => onLogin(email, pass)}>Войти в рай</button>
      </div>
    </div>
  );
}
